#include <stdio.h>
#include <stdbool.h>

#define MAX_MEMORY 1000

typedef struct {
    int start;
    int size;
    bool allocated;
    char process_id;
} MemoryBlock;

void initialize_memory(MemoryBlock memory[], int *num_blocks) {
    memory[0].start = 0;
    memory[0].size = MAX_MEMORY;
    memory[0].allocated = false;
    memory[0].process_id = -1;
    *num_blocks = 1;
}

int first_fit(MemoryBlock memory[], int num_blocks, int process_size, char pid) {
    for (int i = 0; i < num_blocks; i++) {
        if (!memory[i].allocated && memory[i].size >= process_size) {
            // Found suitable block
            if (memory[i].size > process_size) {
                // Split the block
                for (int j = num_blocks; j > i + 1; j--)
                    memory[j] = memory[j-1];
                memory[i+1].start = memory[i].start + process_size;
                memory[i+1].size = memory[i].size - process_size;
                memory[i+1].allocated = false;
                memory[i+1].process_id = -1;
                num_blocks++;
            }
            memory[i].allocated = true;
            memory[i].process_id = pid;
            memory[i].size = process_size;
            return memory[i].start;
        }
    }
    return -1; // No suitable block found
}

void display_memory(MemoryBlock memory[], int num_blocks) {
    printf("Memory Map:\n");
    for (int i = 0; i < num_blocks; i++) {
        printf("[%d-%d] %s %c\n", 
               memory[i].start, 
               memory[i].start + memory[i].size - 1,
               memory[i].allocated ? "ALLOC" : "FREE",
               memory[i].allocated ? memory[i].process_id : '-');
    }
}
